import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Creates a new job opening for the corporation the user belongs to.
 *
 * Payload:
 * [ title: string, openSlots: number ]
 */
export class JobBoardCreateOpeningComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(title: string, openSlots: number) {
        const safeTitle = String(title || '')
            .trim()
            .substring(0, 64);
        const slots = Math.max(0, Math.floor(openSlots || 0));

        this._data = [safeTitle, slots];

        console.log(
            '[📤] JobBoardCreateOpeningComposer packet sent:',
            this._data
        );
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
